import sys

class Solution:
    def canCross(self, stones: list[int], maxJump: int) -> bool:
        stone_set = set(stones)
        memo = {}

        def dfs(stone, jump):
            if stone == stones[-1]:
                return True
            if (stone, jump) in memo:
                return memo[(stone, jump)]
            for next_stone in range(stone + 1, stone + maxJump + 1):
                if next_stone in stone_set and jump - 1 <= next_stone - stone <= jump + 1:
                    if dfs(next_stone, next_stone - stone):
                        memo[(stone, jump)] = True
                        return True
            memo[(stone, jump)] = False
            return False

        return dfs(stones[0], 0)

