#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool canCross(vector<int>& stones, int maxJump) {
        unordered_set<int> stone_set(stones.begin(), stones.end());
        unordered_map<int, unordered_map<int, bool>> memo;
        return dfs(0, 0, stone_set, maxJump, memo, stones);
    }
private:
    bool dfs(int stone, int jump, unordered_set<int>& stone_set, int maxJump, unordered_map<int, unordered_map<int, bool>>& memo, vector<int>& stones) {
        if (stone == stones.back()) {
            return true;
        }
        if (memo.find(stone) != memo.end() && memo[stone].find(jump) != memo[stone].end()) {
            return memo[stone][jump];
        }
        for (int next_stone = stone + 1; next_stone <= stone + maxJump; next_stone++) {
            if (stone_set.find(next_stone) != stone_set.end() && jump - 1 <= next_stone - stone && next_stone - stone <= jump + 1) {
                if (dfs(next_stone, next_stone - stone, stone_set, maxJump, memo, stones)) {
                    memo[stone][jump] = true;
                    return true;
                }
            }
        }
        memo[stone][jump] = false;
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> stones(n);
    for (int i = 0; i < n; i++) cin >> stones[i];
    int maxJump;
    cin >> maxJump;
    Solution sol;
    bool ans = sol.canCross(stones, maxJump);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
